import{_ as r,C as n,o as i,c as s,j as o,a,E as d,a7 as l}from"./chunks/framework.C4ZIv4ii.js";const w=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md","lastUpdated":1783157793000}'),c={name:"changelog.md"},h={id:"v1-8-1",tabindex:"-1"};function u(g,e,p,m,f,b){const t=n("Badge");return i(),s("div",null,[e[3]||(e[3]=o("h1",{id:"changelog",tabindex:"-1"},[a("Changelog "),o("a",{class:"header-anchor",href:"#changelog","aria-label":'Permalink to "Changelog"'},"​")],-1)),e[4]||(e[4]=o("p",null,[a("All notable changes to "),o("strong",null,"FalconCMS"),a(" are documented here."),o("br"),a(" Format follows "),o("a",{href:"https://keepachangelog.com/en/1.0.0/",target:"_blank",rel:"noreferrer"},"Keep a Changelog"),a(" — versions are sorted newest first.")],-1)),e[5]||(e[5]=o("hr",null,null,-1)),o("h2",h,[e[0]||(e[0]=a("v1.8.1 ",-1)),d(t,{type:"tip",text:"Latest"}),e[1]||(e[1]=a()),e[2]||(e[2]=o("a",{class:"header-anchor",href:"#v1-8-1","aria-label":'Permalink to "v1.8.1 <Badge type="tip" text="Latest" /> {#v1-8-1}"'},"​",-1))]),e[6]||(e[6]=l('<p><strong>Released: 2026-07-04</strong></p><p>A builder-experience &amp; polish release: the page/post builder canvas now previews the real header, page title bar and footer around your content, plus fixes for headings in the classic editor and the admin Customizer menu placement.</p><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Live header / title bar / footer preview in the builder</strong> — when you design a <strong>page, post, CPT or product</strong> (not a Layout template), the canvas now shows the actual <strong>Header</strong>, <strong>Page Title Bar</strong> and <strong>Footer</strong> that the applicable Layout assigns to it, rendered through the real theme so it looks like the live page. They&#39;re <strong>read-only</strong> here — hover shows an <em>Edit … Layout Section</em> button that opens that section in the Layout Builder. A slot is previewed <strong>only when it&#39;s enabled</strong> in the layout.</li></ul><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Rich Editor headings</strong> — the <strong>Paragraph / Heading 1–6</strong> dropdown is back in the classic editor (it was using a removed TinyMCE 5 control name).</li><li><strong>Customizer now lives under Falcon Builder</strong> on existing sites too — a migration moves the <em>Customizer</em> menu item out of <em>Appearance</em> and under <em>Falcon Builder</em> (fresh installs already got this); a legacy <em>&quot;Lazy Builder&quot;</em> menu is renamed to <em>Falcon Builder</em>.</li><li><strong>Disabled Layout slots render nothing</strong> — when the Layout Builder is in use, a header/title-bar/footer that is toggled <strong>off</strong> or unassigned no longer falls back to the theme&#39;s built-in chrome (on the frontend <em>and</em> in the builder preview).</li></ul><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Classic-editor headings now use your Customizer heading sizes</strong> instead of shrinking to paragraph size (Tailwind&#39;s preflight was overriding bare <code>h1</code>–<code>h6</code>; the page builder was already unaffected).</li><li><strong>Hairline gap</strong> between the page content and a full-width footer (a 1px sub-pixel seam showing the body background) is gone.</li><li>Fixed an infinite recursion that could return a 500 when a page is rendered as its own content (e.g. the Home page inside its assigned footer).</li></ul><h2 id="v1-8-0" tabindex="-1">v1.8.0 <a class="header-anchor" href="#v1-8-0" aria-label="Permalink to &quot;v1.8.0 {#v1-8-0}&quot;">​</a></h2><p><strong>Released: 2026-07-03</strong></p><p>A major builder release: a dedicated <strong>Layout Builder</strong> for site-wide templates, a new <strong>Bread Crumb</strong> element, <strong>dynamic image backgrounds</strong> for containers and columns, and a far more consistent <strong>Site Width / Full Width</strong> system.</p><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Layout Builder</strong> — design site-wide <strong>Header</strong>, <strong>Footer</strong>, <strong>Page Title Bar</strong> and <strong>Content</strong> templates in the Falcon Builder and assign them globally or by condition. Includes an in-card layout picker, a <strong>conditions</strong> modal (target a custom layout to specific pages, post types or archives), a per-layout <strong>enable/disable</strong> toggle (AJAX), and <strong>Export / Import</strong> of layouts.</li><li><strong>Custom 404 page</strong> — build your own &quot;Not Found&quot; page in the Layout Builder; the theme renders it automatically.</li><li><strong>Bread Crumb element</strong> — a new builder element that outputs the current page&#39;s breadcrumb trail (Home → post type / category → current page), with full typography, colour, separator and alignment controls, plus Schema.org <code>BreadcrumbList</code> structured data for SEO.</li><li><strong>Dynamic image backgrounds</strong> — containers, columns and nested columns can now use a <strong>dynamic source</strong> (Feature Image, Author Avatar or Site Logo) as their Background Image, resolved per-post on the frontend. It layers correctly beneath a Background Gradient, and the builder canvas previews it too.</li></ul><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Consistent Site Width / Full Width</strong> — a container set to <strong>Site Width</strong> now always constrains to your Customizer <em>Site Width</em> (centered), independent of the Customizer&#39;s Boxed/Wide layout, and matches the builder canvas exactly. <strong>Full Width</strong> containers always span edge-to-edge.</li><li><strong>Customizer moved under Falcon Builder</strong> — <em>Appearance → Customize</em> now lives in the <strong>Falcon Builder</strong> menu; the sidebar&#39;s &quot;Lazy Builder&quot; was renamed to <strong>Falcon Builder</strong> with corrected submenu links, and the standalone Header/Footer builder entries were removed (they live in the Layout Builder now).</li><li><strong>Product sorting</strong> on the shop and product archives only appears when products actually exist.</li><li><strong>Hardened ACPT import/export</strong> — re-imports are idempotent, taxonomy terms keep their <code>cpt_slug</code>, and post export is more complete.</li></ul><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>The <strong>Post Content</strong> element set to <em>Full content</em> no longer breaks plain/classic content out to the viewport edge — it now respects its parent container&#39;s width (it still full-bleeds when the content is itself a builder layout with self-boxing sections).</li><li>Dynamic backgrounds render <strong>inline</strong> (no lazy-load dependency) so they paint reliably; the builder canvas shows a neutral <strong>&quot;Feature Image&quot;</strong> placeholder when editing a template that has no specific post, instead of an unrelated image.</li></ul><h2 id="v1-7-4" tabindex="-1">v1.7.4 <a class="header-anchor" href="#v1-7-4" aria-label="Permalink to &quot;v1.7.4 {#v1-7-4}&quot;">​</a></h2><p><strong>Released: 2026-06-30</strong></p><p>A portability &amp; accounts release: import/export for forms and builder-library items, an email-verification toggle, and a much smarter media backup/restore. Now officially runs on <strong>Laravel 13</strong> as well.</p><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Form import/export</strong> — every form can be exported to a portable <code>.json</code> file (structure + settings) and imported on any FalconCMS site as a new form, straight from the Forms list</li><li><strong>Post Card &amp; Mega Menu import/export</strong> — builder-library items export to <code>.json</code> and import back as new items (with fresh IDs), so designs move easily between sites</li><li><strong>&quot;Require email verification&quot; toggle</strong> — <em>Settings → Membership</em> now lets the site owner choose whether new users must verify their email before signing in, or are logged in immediately after registering</li></ul><h3 id="changed-2" tabindex="-1">Changed <a class="header-anchor" href="#changed-2" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Smarter media backup &amp; restore</strong> — a <em>media-only</em> backup now bundles the Media Library records too, so restoring brings the library entries back (not just the files); restore also <strong>auto-detects and strips a wrapper folder</strong> (e.g. when a downloaded backup was unzipped and re-zipped), and preserves the full <code>Year/Month</code> folder structure</li><li><strong>Deleting a media item now removes its generated size variants</strong> too (e.g. <code>image-300x200.jpg</code>), matching WordPress — files that are tracked as their own media item are left alone</li><li><strong>Honest registration feedback</strong> — if the verification email can&#39;t be sent, registration now says so plainly instead of falsely claiming a link was sent</li><li><strong>Laravel 13 support</strong> — added to the documented requirements (Laravel 10, 11, 12, or 13)</li></ul><h3 id="fixed-2" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-2" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Media-only restore now places files at their correct paths (including the <code>media/</code> sub-folder) instead of flattening them</li></ul><h2 id="v1-7-3" tabindex="-1">v1.7.3 <a class="header-anchor" href="#v1-7-3" aria-label="Permalink to &quot;v1.7.3 {#v1-7-3}&quot;">​</a></h2><p><strong>Released: 2026-06-30</strong></p><p>A tooling &amp; migration release: a new Export/Import pair, one-click Clone for every content type, a smarter Backup tool, plus several builder, security and migration fixes.</p><h3 id="added-3" tabindex="-1">Added <a class="header-anchor" href="#added-3" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Tools → Export</strong> — a feature-driven export screen: it lists every registered post type, taxonomy and the media library automatically (so future exportable features appear on their own) and downloads a WordPress-compatible <code>.xml</code> (WXR) file. Pick <strong>All content</strong> or a single source</li><li><strong>Tools → Import</strong> — the counterpart to Export: upload an export <code>.xml</code> and it restores posts, pages, custom post types and taxonomy terms (also accepts standard WordPress WXR files)</li><li><strong>Clone for posts, pages, products &amp; CPTs</strong> — every list row now has a <strong>Clone</strong> action (next to View) that duplicates the item — and its taxonomies, custom fields and (for products) shop data, variations &amp; downloads — into a fresh draft</li><li><strong>Duplicate menu</strong> — the menu editor gains a <strong>Duplicate Menu</strong> action that copies a navigation menu with its full item hierarchy (the copy is never auto-assigned as header/footer)</li></ul><h3 id="changed-3" tabindex="-1">Changed <a class="header-anchor" href="#changed-3" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Backup tool reworked</strong> — one <strong>Create Backup</strong> button with three choices: <strong>Only Database</strong>, <strong>Only Media</strong>, or <strong>Database + Media</strong> (a single archive carrying both). Restore is now content-aware — it detects from the file itself whether to restore the database, the media, or both, so a whole site can be moved to another install with one file. Uploaded backups are detected the same way</li><li><strong>Live gallery hover effect on the canvas</strong> — the Gallery element&#39;s <em>Zoom</em> hover now previews in the builder, matching the front end</li><li><strong>Column / nested-column hover effects now work on the front end</strong> — <em>Zoom / Lift / Glow / Fade</em> hover types rendered only in the builder before; they now render on the published page too</li><li><strong>Buttons without a link render cleanly</strong> — a Button with an empty <strong>Link URL</strong> no longer outputs an empty <code>&lt;a&gt;</code> tag or a pointer cursor; any value (including <code>#</code>) makes it a real link again</li><li><strong>Clearer import results</strong> — re-importing items that already exist now reports them as <em>skipped</em> (including taxonomy terms) with an explanatory note, instead of showing all zeros</li></ul><h3 id="fixed-3" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-3" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Stored-XSS hardening</strong> — classic (non-builder) post/page content is now sanitised on output (scripts, <code>on*</code> handlers and <code>javascript:</code> URLs are stripped), closing a gap that affected imported HTML content</li><li><strong>Menu save error</strong> — saving a menu no longer fails with <em>Unknown column <code>mega_menu_id</code></em>; the relevant migration now runs, and several migrations were made <strong>idempotent</strong> (guarded with <code>hasTable</code>/<code>hasColumn</code>) so <code>php artisan migrate</code> runs cleanly on fresh, partially-migrated or already-migrated installs — <strong>without any data loss</strong></li><li><strong>Menu selector</strong> — choosing a menu from the dropdown no longer auto-opens it; the <strong>Select</strong> button is the trigger</li><li><strong>Nested-row layout consistency</strong> on the builder canvas</li></ul><h2 id="v1-7-2" tabindex="-1">v1.7.2 <a class="header-anchor" href="#v1-7-2" aria-label="Permalink to &quot;v1.7.2 {#v1-7-2}&quot;">​</a></h2><p><strong>Released: 2026-06-27</strong></p><p>A builder polish &amp; tooling release: every Font Awesome free icon in the icon pickers, a media-files backup option, plus several nested-layout and colour-picker fixes that make the builder canvas match the front end.</p><h3 id="added-4" tabindex="-1">Added <a class="header-anchor" href="#added-4" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Media files backup</strong> — <em>Tools → Backup</em> now has a <strong>Backup Media Files</strong> button that zips everything under <code>storage/app/public</code> (uploads, generated images, etc.) into a downloadable archive, and restores media archives back into place. Database snapshots are unchanged</li><li><strong>Every Font Awesome free icon in the builder</strong> — the icon pickers (Icon Box, Button icon, Icon List and custom icon fields) now list the full Font Awesome 6 free set — <strong>2,060 icons</strong> across Solid, Regular and Brands (up from a few hundred). A search box reaches any icon, with the grid capped for snappy scrolling</li></ul><h3 id="changed-4" tabindex="-1">Changed <a class="header-anchor" href="#changed-4" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Icon Box font size accepts any CSS unit</strong> — the Title and Description <strong>Font Size</strong> fields lost their <code>px</code>/<code>rem</code> dropdown and now take a free-form value (<code>px</code>, <code>rem</code>, <code>em</code>, <code>%</code>, <code>vw</code>, <code>vh</code>, <code>calc()</code>), matching the Title element</li><li><strong>Nested-column Border &amp; Box-Shadow colour pickers unified</strong> — they now use the same round-swatch + editable hex design as every other picker, show the opacity-aware <code>#RRGGBBAA</code> code, and the colour renders <strong>with its opacity</strong> on canvas and front end (responsive per-device)</li></ul><h3 id="fixed-4" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-4" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Nested rows match the front end on the canvas</strong> — a nested row no longer shows a permanent whitish box; it renders transparent (like a normal element) and reveals its outline + <strong>ROW</strong> badge only on hover, with no extra padding gap between the row and its parent</li><li><strong>No more phantom vertical gap inside nested columns</strong> — columns with <strong>default</strong> alignment no longer stretch their inner content to a taller sibling&#39;s height in the builder, so spacing inside nested columns now looks exactly like the published page</li></ul><h2 id="v1-7-1" tabindex="-1">v1.7.1 <a class="header-anchor" href="#v1-7-1" aria-label="Permalink to &quot;v1.7.1 {#v1-7-1}&quot;">​</a></h2><p><strong>Released: 2026-06-26</strong></p><h3 id="changed-5" tabindex="-1">Changed <a class="header-anchor" href="#changed-5" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Analytics &quot;Page&quot; column shows the site domain for homepage visits</strong> — homepage hits (including bots that reach the site by raw IP) now display the configured site domain (e.g. <code>demo.example.com</code>) instead of a bare <code>/</code>. Other pages still show their request path</li></ul><h2 id="v1-7-0" tabindex="-1">v1.7.0 <a class="header-anchor" href="#v1-7-0" aria-label="Permalink to &quot;v1.7.0 {#v1-7-0}&quot;">​</a></h2><p><strong>Released: 2026-06-26</strong></p><p>A builder &amp; design-tooling release: one unified colour picker everywhere, responsive background <strong>hover</strong> colours, full CSS-unit support for font sizes, plus several builder and analytics fixes.</p><h3 id="added-5" tabindex="-1">Added <a class="header-anchor" href="#added-5" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Background Hover Color for Containers, Columns &amp; Nested Columns</strong> — a new <strong>responsive</strong> hover colour (separate desktop / tablet / mobile values). It previews live on hover in the builder canvas and renders as a real <code>:hover</code> rule (with media queries) on the front end</li><li><strong>Custom Text Color for Buttons</strong> — when <em>Button Style → Custom</em> is selected, a dedicated text-colour picker sits with the gradient colours; the default style keeps its own text colour</li></ul><h3 id="changed-6" tabindex="-1">Changed <a class="header-anchor" href="#changed-6" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>One unified colour picker across the whole CMS</strong> — the main builder, the mega-menu &amp; post-card builders, the Theme Customizer and the Form builder now share a single clean picker: a round swatch, an editable hex field, and a compact popup (saturation square + hue + alpha sliders) with the <strong>alpha bar tinted to the current colour</strong>. The Form-builder picker also gained an <strong>opacity slider</strong></li><li><strong>Opacity-aware colour fields</strong> — fields that store opacity separately now show the full 8-digit <code>#RRGGBBAA</code> code, and the alpha slider opens at the correct position</li><li><strong>CSS units for every font size</strong> — all typography / font-size inputs across builder elements (and inside header / footer / nested layouts) now accept <code>px</code>, <code>rem</code>, <code>em</code>, <code>%</code>, <code>vw</code>, <code>vh</code> and <code>calc()</code>. Values apply on both the canvas and the front end and survive the shortcode round-trip</li><li><strong>Title element typography</strong> now mirrors the Text Block (font family, weight, size, line-height, letter-spacing, transform) for a consistent editing experience</li></ul><h3 id="fixed-5" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-5" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Column / nested-column background colour ignored responsive values</strong> — tablet/mobile background colours were rendered with the desktop value on both the canvas and the front end; per-device colours are now honoured</li><li><strong>A per-device colour was discarded when switching device</strong> — picking a tablet/mobile colour and then toggling the device preview reverted it; the colour is now committed instead of reverted</li><li><strong>Analytics &quot;Page&quot; column showed the raw server IP</strong> — visitors who reached the site directly by IP (bots/scanners) appeared as <code>https://&lt;ip&gt;</code>; the column now shows a clean request path</li><li><strong>Documentation</strong> clarifies that <strong>MySQL / MariaDB</strong> are the only fully supported databases (SQLite is partial and not recommended; PostgreSQL / SQL Server are unsupported)</li></ul><h2 id="v1-6-3" tabindex="-1">v1.6.3 <a class="header-anchor" href="#v1-6-3" aria-label="Permalink to &quot;v1.6.3 {#v1-6-3}&quot;">​</a></h2><p><strong>Released: 2026-06-25</strong></p><h3 id="fixed-6" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-6" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Reinstalling over an existing database failed with &quot;table already exists&quot;</strong> — Running <code>falcon:install</code> (or <code>falcon:update</code>) on top of a database that still had some tables — after <code>falcon:uninstall-db</code>, or when installing onto an existing Laravel app whose <code>users</code> / <code>cache</code> / <code>jobs</code> tables remained — made <code>migrate</code> try to recreate them and abort. The commands now <strong>reconcile first</strong>: any migration whose created tables already exist is recorded as run, so <code>migrate</code> skips it and only creates what is genuinely missing. This works for both the app&#39;s own and the package&#39;s migrations, without editing any migration file</li></ul><h2 id="v1-6-2" tabindex="-1">v1.6.2 <a class="header-anchor" href="#v1-6-2" aria-label="Permalink to &quot;v1.6.2 {#v1-6-2}&quot;">​</a></h2><p><strong>Released: 2026-06-24</strong></p><h3 id="fixed-7" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-7" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Uninstall could leave a broken <code>User</code> model</strong> — <code>falcon:uninstall</code> removed the <code>HasCmsPermissions</code> import but only stripped a <em>standalone</em> <code>use HasCmsPermissions;</code> line. When the trait was declared in a combined list (e.g. <code>use HasFactory, Notifiable, HasCmsPermissions;</code>), the reference was left without its import, crashing the app — and any later reinstall&#39;s migrations — with <em>&quot;Trait App\\Models\\HasCmsPermissions not found&quot;</em>. The revert now also removes the trait from a combined <code>use</code> list (verified valid for leading/middle/trailing positions)</li></ul><h2 id="v1-6-1" tabindex="-1">v1.6.1 <a class="header-anchor" href="#v1-6-1" aria-label="Permalink to &quot;v1.6.1 {#v1-6-1}&quot;">​</a></h2><p><strong>Released: 2026-06-24</strong></p><h3 id="fixed-8" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-8" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Dashboard showed a stale &quot;Installed Version&quot;</strong> — After updating, the dashboard kept showing an old installed version (e.g. v1.4.2) even though the new code was in place. The version check preferred Composer&#39;s reported version, which can be a pinned alias (notably on path-repository installs) and lags behind. It now reads the version from the package&#39;s <code>version.json</code> first (bumped on every release), so the dashboard reflects the version actually installed</li></ul><h2 id="v1-6-0" tabindex="-1">v1.6.0 <a class="header-anchor" href="#v1-6-0" aria-label="Permalink to &quot;v1.6.0 {#v1-6-0}&quot;">​</a></h2><p><strong>Released: 2026-06-24</strong></p><p>A consolidation milestone that brings together everything shipped across the 1.5.x line.</p><h3 id="highlights" tabindex="-1">Highlights <a class="header-anchor" href="#highlights" aria-label="Permalink to &quot;Highlights&quot;">​</a></h3><ul><li><strong>Dashboard</strong> — Redesigned e-commerce KPI cards with month-over-month trend deltas; <strong>Top Selling Products</strong>, <strong>Low Stock</strong> and <strong>Recent Orders</strong> widgets; and an interactive <strong>Orders by Country</strong> world map (zoom, pan and per-country hover). The whole e-commerce section is now gated behind the <code>access_shop</code> permission</li><li><strong>Analytics</strong> — A <strong>Visitors by Country</strong> world map, a named <strong>Traffic Sources</strong> breakdown (Google, Facebook, Instagram, YouTube, … Direct, and other sites), and hover tooltips on the real-time active-users sparkline</li><li><strong>Shop</strong> — The <strong>Conversion Funnel</strong> (visitors → product → cart → checkout → orders) now lives on the Shop Overview</li><li><strong>Security &amp; reliability</strong> — Internal AJAX fragment endpoints redirect on direct visits instead of leaking raw JSON; reliable geolocation via the shared <code>falcon_geoip()</code> helper; a richer IP blacklist (location, ISP, first/last seen)</li><li><strong>Lifecycle</strong> — New <code>falcon:uninstall</code> (full, leaves the app booting cleanly) and <code>falcon:uninstall-db</code> (database-only) commands, plus idempotent core migrations so a reinstall always succeeds</li></ul><p>For the granular history of these changes, see the 1.5.x entries below.</p><h2 id="v1-5-10" tabindex="-1">v1.5.10 <a class="header-anchor" href="#v1-5-10" aria-label="Permalink to &quot;v1.5.10 {#v1-5-10}&quot;">​</a></h2><p><strong>Released: 2026-06-24</strong></p><h3 id="fixed-9" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-9" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>App crashed after a database reset</strong> — The redirect middleware queried <code>cms_redirects</code> on every request and returned a 500 (<em>&quot;Base table or view not found&quot;</em>) once the tables were dropped (e.g. after <code>falcon:uninstall-db</code>). It now checks the table exists first and degrades gracefully when it doesn&#39;t</li><li><strong>Reinstall failed with &quot;table already exists&quot;</strong> — Uninstall keeps the shared Laravel tables (<code>users</code>, <code>sessions</code>, <code>cache</code>, <code>jobs</code>) but clears the migration records, so re-running <code>falcon:install</code> / <code>migrate</code> tried to recreate them and failed with <em>&quot;Table &#39;users&#39; already exists&quot;</em>. The bundled <code>users</code> / <code>cache</code> / <code>jobs</code> migrations are now idempotent (<code>Schema::hasTable</code> guards), so a reinstall succeeds no matter which tables remain</li></ul><h2 id="v1-5-9" tabindex="-1">v1.5.9 <a class="header-anchor" href="#v1-5-9" aria-label="Permalink to &quot;v1.5.9 {#v1-5-9}&quot;">​</a></h2><p><strong>Released: 2026-06-24</strong></p><h3 id="fixed-10" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-10" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Uninstall left a stale provider cache</strong> — <code>falcon:uninstall</code> removes the package with <code>composer remove --no-scripts</code>, which doesn&#39;t regenerate Laravel&#39;s package-discovery cache. <code>bootstrap/cache/packages.php</code> / <code>services.php</code> therefore still referenced <code>FalconCmsServiceProvider</code>, so the app booted with <em>&quot;Class FalconCms\\Core\\FalconCmsServiceProvider not found&quot;</em>. The command now clears those bootstrap caches as its final step. (If you hit this after a manual <code>composer remove</code>, delete <code>bootstrap/cache/packages.php</code> and <code>bootstrap/cache/services.php</code>, then run <code>composer dump-autoload</code>.)</li></ul><h2 id="v1-5-8" tabindex="-1">v1.5.8 <a class="header-anchor" href="#v1-5-8" aria-label="Permalink to &quot;v1.5.8 {#v1-5-8}&quot;">​</a></h2><p><strong>Released: 2026-06-24</strong></p><h3 id="fixed-11" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-11" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Uninstall left a broken <code>User</code> model</strong> — The earlier uninstall dropped tables and files but did not remove the <code>HasCmsPermissions</code> trait the installer added to <code>App\\Models\\User</code>, so after <code>composer remove</code> the app crashed with <em>&quot;Trait FalconCms\\Core\\Traits\\HasCmsPermissions not found&quot;</em>. The full uninstall now reverts that automatically</li></ul><h3 id="added-6" tabindex="-1">Added <a class="header-anchor" href="#added-6" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong><code>falcon:uninstall</code> — full removal (no leftovers)</strong> — Reverts the trait/import added to <code>App\\Models\\User</code>, drops tables + migration records, removes published files, and runs <code>composer remove falconcms/falconcms</code> — leaving the app booting cleanly. Options: <code>--all</code> (also drop shared Laravel tables), <code>--force</code>, <code>--keep-files</code>, <code>--no-composer</code></li><li><strong><code>falcon:uninstall-db</code> — database-only removal</strong> — Drops just the FalconCMS tables (and migration records); the package code, files and User model trait stay in place (e.g. to wipe data and re-<code>migrate</code>). Options: <code>--all</code>, <code>--force</code></li></ul><h2 id="v1-5-7" tabindex="-1">v1.5.7 <a class="header-anchor" href="#v1-5-7" aria-label="Permalink to &quot;v1.5.7 {#v1-5-7}&quot;">​</a></h2><p><strong>Released: 2026-06-24</strong></p><h3 id="added-7" tabindex="-1">Added <a class="header-anchor" href="#added-7" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong><code>falcon:uninstall</code> command</strong> — Cleanly removes FalconCMS: drops its database tables, deletes its rows from the <code>migrations</code> table (so a later reinstall re-runs cleanly), and removes published views, themes and assets. Shared Laravel tables (<code>users</code>, <code>sessions</code>, <code>cache</code>, <code>jobs</code>, …) are <strong>kept by default</strong> to avoid breaking the host app; <code>--all</code> drops them too for a full wipe. Options: <code>--force</code> (skip the confirmation), <code>--all</code>, <code>--keep-files</code>. Finish with <code>composer remove falconcms/falconcms</code></li></ul><h2 id="v1-5-6" tabindex="-1">v1.5.6 <a class="header-anchor" href="#v1-5-6" aria-label="Permalink to &quot;v1.5.6 {#v1-5-6}&quot;">​</a></h2><p><strong>Released: 2026-06-24</strong></p><h3 id="fixed-12" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-12" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>IP Blacklist — country always &quot;Unknown&quot;</strong> — Blocked IPs were geo-resolved with <code>file_get_contents</code>, which is disabled or blocked on many production hosts, so the country never resolved. A new shared <code>falcon_geoip()</code> helper now uses the Laravel HTTP client (with a timeout, cached 30 days); existing &quot;Unknown&quot; rows are backfilled when the blacklist page is viewed</li></ul><h3 id="added-8" tabindex="-1">Added <a class="header-anchor" href="#added-8" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>IP Blacklist — richer detail</strong> — The blacklist table now shows <strong>Location</strong> (country + city/region), <strong>ISP / network</strong>, and both <strong>First Blocked</strong> and <strong>Last Attempt</strong> times, with an attempts badge. New blocks capture city, region and ISP</li></ul><h3 id="changed-7" tabindex="-1">Changed <a class="header-anchor" href="#changed-7" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Geo lookups unified</strong> — Visit tracking and the IP blacklist now share the same cached <code>falcon_geoip()</code> helper instead of separate, less reliable lookups</li></ul><h2 id="v1-5-5" tabindex="-1">v1.5.5 <a class="header-anchor" href="#v1-5-5" aria-label="Permalink to &quot;v1.5.5 {#v1-5-5}&quot;">​</a></h2><p><strong>Released: 2026-06-24</strong></p><h3 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h3><ul><li><strong>AJAX fragment endpoints no longer expose raw output on direct visit</strong> — <code>GET /cart/fragment</code> (mini-cart) and <code>GET /search/live</code> are internal AJAX-only endpoints; opening them directly in a browser previously returned their raw JSON. Non-AJAX (direct navigation) requests are now redirected to the cart and search pages respectively, so the raw payloads are never shown. JS-driven calls (which send <code>X-Requested-With</code>) are unaffected, and only ever returned the visitor&#39;s own session data anyway</li></ul><h2 id="v1-5-4" tabindex="-1">v1.5.4 <a class="header-anchor" href="#v1-5-4" aria-label="Permalink to &quot;v1.5.4 {#v1-5-4}&quot;">​</a></h2><p><strong>Released: 2026-06-24</strong></p><h3 id="added-9" tabindex="-1">Added <a class="header-anchor" href="#added-9" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Dashboard — Orders by Country map</strong> — An interactive world map highlighting the countries orders came from (shaded by volume), with zoom buttons, mouse-wheel zoom, drag-to-pan and per-country hover (country name + order count), plus a top-countries list. Country values are normalized to ISO-2 from mixed order data</li><li><strong>Dashboard — Top Selling Products, Low Stock &amp; Recent Orders</strong> — The redundant &quot;Quick Stats&quot; panel is replaced by a best-sellers list (units sold + revenue) and a low-stock alert list; a Recent Orders table now fills the space under the revenue chart</li><li><strong>Analytics — Visitors by Country map</strong> — The same interactive world map for geo-located visits</li><li><strong>Analytics — Traffic Sources</strong> — A named-source breakdown (Google, Bing, Facebook, Instagram, YouTube, X, LinkedIn, TikTok, … Direct, and any other site by domain) with visit counts, percentages and favicons</li><li><strong>Analytics — Real-time sparkline tooltip</strong> — Hovering the real-time active-users bars now shows the visitor count for that minute</li></ul><h3 id="changed-8" tabindex="-1">Changed <a class="header-anchor" href="#changed-8" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Dashboard — E-commerce KPI cards redesigned</strong> — Accent strip, soft-tint icon, month-over-month trend delta (↑/↓ %) and a contextual subtext per card</li><li><strong>Dashboard — Shop section permission-gated</strong> — The whole e-commerce section (revenue, orders, customer names) now requires the <code>access_shop</code> permission (admins bypass), so it is no longer shown to every dashboard-accessing role</li><li><strong>Shop → Overview — Conversion Funnel</strong> — The conversion funnel (visitors → product → cart → checkout → orders) and conversion rate now live on the Shop Overview, moved from Analytics to keep shop metrics together</li></ul><h2 id="v1-5-3" tabindex="-1">v1.5.3 <a class="header-anchor" href="#v1-5-3" aria-label="Permalink to &quot;v1.5.3 {#v1-5-3}&quot;">​</a></h2><p><strong>Released: 2026-06-23</strong></p><h3 id="fixed-13" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-13" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Registration — default role ignored</strong> — Self-registration now assigns the role configured in <strong>Settings → New User Default Role</strong> instead of always using <em>subscriber</em>. Selecting a different role (e.g. Editor, Author) now correctly applies it to newly registered users; if the configured role is missing it safely falls back to subscriber</li></ul><h2 id="v1-5-2" tabindex="-1">v1.5.2 <a class="header-anchor" href="#v1-5-2" aria-label="Permalink to &quot;v1.5.2 {#v1-5-2}&quot;">​</a></h2><p><strong>Released: 2026-06-23</strong></p><h3 id="changed-9" tabindex="-1">Changed <a class="header-anchor" href="#changed-9" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Device limit — simpler on/off model</strong> — The multi-device setting is now a clear cap. <strong>Unchecked = unlimited</strong> devices; <strong>checked = limit</strong> concurrent logins to <em>Max devices allowed</em>. The <code>-1</code> &quot;unlimited&quot; sentinel has been removed — the field is a plain positive number again (minimum 1), and the checkbox/help text now reflect the inverted meaning</li></ul><h2 id="v1-5-1" tabindex="-1">v1.5.1 <a class="header-anchor" href="#v1-5-1" aria-label="Permalink to &quot;v1.5.1 {#v1-5-1}&quot;">​</a></h2><p><strong>Released: 2026-06-23</strong></p><h3 id="fixed-14" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-14" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Multi-device login — unlimited (<code>-1</code>)</strong> — Setting <strong>Max devices allowed</strong> to <code>-1</code> now correctly means unlimited concurrent sessions and never blocks sign-in. Previously the limit check (<code>active sessions ≥ -1</code>) was always true, so logging in from a second device failed with <em>&quot;Login denied: Only one active session is allowed per account.&quot;</em> The <code>-1</code> sentinel now applies regardless of the multi-device toggle; normal numeric limits and the single-session default are unchanged</li></ul><h3 id="changed-10" tabindex="-1">Changed <a class="header-anchor" href="#changed-10" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Settings — Max devices allowed</strong> — The field now accepts <code>-1</code> (minimum lowered from <code>1</code>) with a helper note that <code>-1</code> means unlimited devices</li></ul><h2 id="v1-5-0" tabindex="-1">v1.5.0 <a class="header-anchor" href="#v1-5-0" aria-label="Permalink to &quot;v1.5.0 {#v1-5-0}&quot;">​</a></h2><p><strong>Released: 2026-06-22</strong></p><h3 id="fixed-15" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-15" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Registration — duplicate username</strong> — Usernames derived from the email local part are now sanitized and made unique (<code>john@a.com</code> and <code>john@b.com</code> no longer collide → <code>john</code>, <code>john1</code>…), fixing the duplicate-username error on sign-up</li><li><strong>Admin user create/edit</strong> — Validation errors are now displayed (a top summary plus per-field messages) instead of a database constraint crash; inputs repopulate on failure, and a success message is shown</li><li><strong>User update redirect</strong> — Saving a user now returns to the same edit page with the success notice, instead of jumping to the user list</li></ul><h3 id="added-10" tabindex="-1">Added <a class="header-anchor" href="#added-10" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Password strength &amp; match</strong> — The admin user create/edit password fields now show a live strength meter and a password-match indicator, matching the registration page</li></ul><h2 id="v1-4-9" tabindex="-1">v1.4.9 <a class="header-anchor" href="#v1-4-9" aria-label="Permalink to &quot;v1.4.9 {#v1-4-9}&quot;">​</a></h2><p><strong>Released: 2026-06-22</strong></p><h3 id="added-11" tabindex="-1">Added <a class="header-anchor" href="#added-11" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Analytics — major overhaul</strong> — Bot/crawler filtering, geo location (country/city with flags), real-time active users with a 30-minute sparkline and live tables, sessions, bounce rate, new vs returning visitors, traffic channels, e-commerce conversion KPIs and a visit→cart→checkout→order funnel, plus donut charts for channels, returning visitors and top countries</li><li><strong>Analytics — data retention</strong> — New <code>falcon:prune-analytics</code> command with a daily schedule and a cron-independent fallback, with a configurable retention window</li></ul><h3 id="fixed-16" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-16" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Footer logo</strong> — The default footer logo now uses the white brand logo (the dark logo was invisible on the dark footer) at a larger size, automatically darkened on light footer backgrounds; a custom uploaded logo is always shown as-is</li></ul><h2 id="v1-4-8" tabindex="-1">v1.4.8 <a class="header-anchor" href="#v1-4-8" aria-label="Permalink to &quot;v1.4.8 {#v1-4-8}&quot;">​</a></h2><p><strong>Released: 2026-06-22</strong></p><h3 id="added-12" tabindex="-1">Added <a class="header-anchor" href="#added-12" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Registration — email verification</strong> — New sign-ups are no longer logged in immediately; a time-limited (5-minute) signed verification link is emailed instead, and sign-in is blocked until the address is verified. Includes a notice page and a throttled resend flow. A migration marks all existing users as verified so no one is locked out</li></ul><h3 id="fixed-17" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-17" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Order status emails</strong> — Customers are now emailed on every order status change (pending, on-hold, processing, completed, delivered, cancelled, refunded, partially-refunded, failed), not just on delivery — for both single and bulk updates</li></ul><h3 id="changed-11" tabindex="-1">Changed <a class="header-anchor" href="#changed-11" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Product Meta element</strong> — Now available only in post-card mode, like Post Meta and Content</li></ul><h2 id="v1-4-7" tabindex="-1">v1.4.7 <a class="header-anchor" href="#v1-4-7" aria-label="Permalink to &quot;v1.4.7 {#v1-4-7}&quot;">​</a></h2><p><strong>Released: 2026-06-21</strong></p><h3 id="added-13" tabindex="-1">Added <a class="header-anchor" href="#added-13" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Builder — Product Meta element</strong> — A new element that displays a product&#39;s price (with sale), SKU, availability, stock quantity and type; each field toggleable, with stacked/inline layout, alignment, labels and full design controls</li><li><strong>Builder — Ticker</strong> — Configurable item spacing, a duplicate-item button, and live scrolling in the builder canvas</li><li><strong>Dynamic sources — Product group</strong> — Bind any text field to live product data (price, regular/sale price, SKU, stock status, stock quantity); dynamic fields now show a live preview right in the builder using the real value of the post being edited</li></ul><h2 id="v1-4-6" tabindex="-1">v1.4.6 <a class="header-anchor" href="#v1-4-6" aria-label="Permalink to &quot;v1.4.6 {#v1-4-6}&quot;">​</a></h2><p><strong>Released: 2026-06-21</strong></p><h3 id="fixed-18" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-18" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong><code>falcon:update</code> — stale published view overrides</strong> — Update now removes the entire published <code>resources/views/vendor/falcon-cms</code> directory, not just the <code>admin</code> subfolder. A leftover published copy of a namespaced package view (e.g. <code>frontend/builder/column.blade.php</code>) silently shadows the real vendor view, so layout fixes never appear on the site no matter how many caches are cleared. Clearing the whole override namespace guarantees the package&#39;s own views are always used</li></ul><h2 id="v1-4-5" tabindex="-1">v1.4.5 <a class="header-anchor" href="#v1-4-5" aria-label="Permalink to &quot;v1.4.5 {#v1-4-5}&quot;">​</a></h2><p><strong>Released: 2026-06-21</strong></p><h3 id="fixed-19" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-19" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Dashboard Update — stale frontend after update</strong> — The dashboard &quot;Update&quot; now resets the php-fpm OPcache from the web request itself. Previously the <code>falcon:update</code> subprocess ran under CLI php, whose <code>opcache_reset()</code> only clears the CLI OPcache — the php-fpm workers that serve frontend pages kept executing the old compiled Blade views, so builder/layout fixes did not appear on the live site until a manual container restart</li><li><strong>Dashboard footer</strong> — Default admin footer credit changed to &quot;Theme developed by Falcon CMS&quot;</li></ul><h3 id="changed-12" tabindex="-1">Changed <a class="header-anchor" href="#changed-12" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Taxonomy screens</strong> — Removed the non-functional &quot;Screen Options&quot; and &quot;Help&quot; buttons from the top-right of all taxonomy list pages (Categories, Tags, Product Categories, Product Tags, and custom ACPT taxonomy terms)</li></ul><h2 id="v1-4-4" tabindex="-1">v1.4.4 <a class="header-anchor" href="#v1-4-4" aria-label="Permalink to &quot;v1.4.4 {#v1-4-4}&quot;">​</a></h2><p><strong>Released: 2026-06-21</strong></p><h3 id="fixed-20" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-20" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Dashboard Update — php-fpm binary</strong> — The dashboard &quot;Update&quot; button ran <code>falcon:update</code> with <code>PHP_BINARY</code>, which in a web (php-fpm) request points at the php-fpm executable and cannot run <code>artisan</code> (it printed FastCGI usage and aborted, so migrations/cache-clear/OPcache reset never ran). The updater now locates a real CLI php binary, checking absolute paths first since the php-fpm worker often runs with a stripped <code>PATH</code></li></ul><h2 id="v1-4-3" tabindex="-1">v1.4.3 <a class="header-anchor" href="#v1-4-3" aria-label="Permalink to &quot;v1.4.3 {#v1-4-3}&quot;">​</a></h2><p><strong>Released: 2026-06-21</strong></p><h3 id="fixed-21" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-21" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Page Builder — Preview mode blank canvas</strong> — Toggling the builder&#39;s eye-icon Preview no longer blanks the whole canvas. In preview the canvas kept <code>grid-area: auto</code>, which auto-placed it into the now-hidden sidebar&#39;s 0-width grid column; it is now pinned to its named <code>canvas</code> area so the design stays visible</li></ul><h2 id="v1-4-2" tabindex="-1">v1.4.2 <a class="header-anchor" href="#v1-4-2" aria-label="Permalink to &quot;v1.4.2 {#v1-4-2}&quot;">​</a></h2><p><strong>Released: 2026-06-21</strong></p><h3 id="fixed-22" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-22" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Page Builder — Row content layout</strong> — Elements inside a column with Content Layout set to &quot;Row&quot; now stay side-by-side and never wrap to the next line (<code>flex-wrap: nowrap</code>); previously <code>flex-wrap: wrap</code> caused elements to stack when they did not fit</li><li><strong><code>falcon:update</code> — OPcache</strong> — OPcache is now reset after cache clearing so freshly compiled Blade views are served immediately without requiring a server restart</li></ul><hr><h2 id="v1-4-1" tabindex="-1">v1.4.1 <a class="header-anchor" href="#v1-4-1" aria-label="Permalink to &quot;v1.4.1 {#v1-4-1}&quot;">​</a></h2><p><strong>Released: 2026-06-21</strong></p><h3 id="fixed-23" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-23" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Multi-device login</strong> — <code>-1</code> value for Max Devices now correctly means unlimited; previously <code>count() &gt;= -1</code> was always true, blocking all logins even when unlimited was intended</li><li><strong>Page Builder — Nested Column row layout</strong> — Elements inside a column with Content Layout set to &quot;Row&quot; now render side-by-side on the frontend; previously <code>width: 100%</code> on element wrappers caused items to stack vertically despite <code>flex-direction: row</code></li></ul><hr><h2 id="v1-4-0" tabindex="-1">v1.4.0 <a class="header-anchor" href="#v1-4-0" aria-label="Permalink to &quot;v1.4.0 {#v1-4-0}&quot;">​</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="added-14" tabindex="-1">Added <a class="header-anchor" href="#added-14" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Demo mode — Login page</strong> — Demo credentials box displayed above login form when <code>APP_DEMO=true</code></li><li><strong>Demo mode — User management</strong> — All fields on user create and user edit pages disabled with warning banner when <code>APP_DEMO=true</code></li><li><strong>Demo mode — Settings</strong> — <code>register_url</code> and <code>login_url</code> inputs disabled with warning banner when <code>APP_DEMO=true</code></li><li><strong>Docs — Demo page</strong> — Live demo request page with lead capture form; credentials sent to visitor&#39;s email via EmailJS after form submission</li></ul><h3 id="fixed-24" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-24" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Footer logo</strong> — Default FalconCMS logo always shown in footer column 1; embedded as base64 to remove file dependency; <code>theme_footer_logo</code> / <code>theme_site_logo</code> cleared from DB on <code>falcon:update</code> so stale overrides are never applied</li><li><strong><code>falcon:update</code></strong> — Published admin views deleted on update so vendor views are always served fresh (no stale published copies)</li></ul><hr><h2 id="v1-3-18" tabindex="-1">v1.3.18 <a class="header-anchor" href="#v1-3-18" aria-label="Permalink to &quot;v1.3.18 {#v1-3-18}&quot;">​</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="added-15" tabindex="-1">Added <a class="header-anchor" href="#added-15" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Customizer — Performance</strong> — &quot;Clear All Cache&quot; button for one-click cache clearing from the admin</li></ul><h3 id="fixed-25" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-25" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Product editor</strong> — Added <code>x-cloak</code> to product data metabox to prevent Alpine.js FOUC on page load</li><li><strong><code>falcon:update</code></strong> — Admin views automatically re-published during update to keep published copies in sync</li><li><strong>Sale end date</strong> — <code>sale_ends_at</code> datetime input minimum set using client-side local time instead of server UTC</li><li><strong>Product archive</strong> — <code>productCategories</code> relation used in <code>archive-product.blade.php</code>; eager loaded on CPT archive queries to prevent N+1</li><li><strong>Sale end date validation</strong> — Removed <code>after:now</code> rule causing false rejections in some timezones</li><li><strong>PHP_BINARY</strong> — Correctly resolved to CLI <code>php</code> in web (php-fpm) context</li><li><strong>Product categories</strong> — Category label display corrected on product cards and single product pages</li><li><strong>Shop</strong> — Tab active-state bug fixed; <code>hold_stock</code> order cancellation implemented</li><li><strong>Page Builder</strong> — Fixed offset constants in <code>parseColumnsFromContent()</code></li><li><strong>Hooks &amp; helpers</strong> — Remaining <code>lazy_</code> class and helper references renamed to <code>falcon_</code></li></ul><hr><h2 id="v1-0-0" tabindex="-1">v1.0.0 <a class="header-anchor" href="#v1-0-0" aria-label="Permalink to &quot;v1.0.0 {#v1-0-0}&quot;">​</a></h2><p><strong>Released: 2026-06-15</strong></p><p>Initial public release of <strong>FalconCMS</strong> — a powerful Laravel CMS package with page builder, e-commerce, and a WordPress-like admin dashboard.</p><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to &quot;Core&quot;">​</a></h3><ul><li><strong>WordPress-like Admin Dashboard</strong> — Sidebar navigation, top bar, role-based permissions, activity logs</li><li><strong>Page Builder (Falcon Builder)</strong> — Drag-and-drop visual editor with rows, columns, and element blocks</li><li><strong>Post &amp; Page Management</strong> — Custom post types, categories, tags, featured images, SEO fields</li><li><strong>Media Library</strong> — Upload, manage, and select images/files across the admin</li><li><strong>User &amp; Role Management</strong> — Granular permission system with custom roles</li><li><strong>Multi-language Support</strong> — Built-in language management</li><li><strong>Theme System</strong> — Installable themes with Customizer support (header, footer, colors, typography)</li><li><strong>Hook Architecture</strong> — WordPress-style <code>add_lazy_action</code> / <code>add_lazy_filter</code> for extensibility</li><li><strong>Custom Options Pages</strong> — Register custom settings pages via config</li></ul><h3 id="e-commerce-shop" tabindex="-1">E-Commerce (Shop) <a class="header-anchor" href="#e-commerce-shop" aria-label="Permalink to &quot;E-Commerce (Shop)&quot;">​</a></h3><ul><li><strong>Product Management</strong> — Simple and variable products, SKU, stock, sale price with scheduled expiry (<code>sale_ends_at</code>)</li><li><strong>Digital / Downloadable Products</strong> — Attach files from the media library; secure token-based download links with expiry and download count limits</li><li><strong>Orders</strong> — Full order lifecycle (pending → processing → shipped → completed), order notes, status history</li><li><strong>Cart &amp; Checkout</strong> — AJAX cart, coupon codes, shipping zones, tax rules</li><li><strong>Payments</strong> — Cash on Delivery, Stripe, SSLCommerz integrations</li><li><strong>Customer Account</strong> — Order history, downloads tab, address management</li><li><strong>Sales Reports</strong> — Revenue by period (daily/weekly/monthly), top products, customer LTV, CSV export</li><li><strong>Shop Settings</strong> — Currency, inventory, email notifications, shipping, tax, coupon management</li></ul><h3 id="admin-ui" tabindex="-1">Admin UI <a class="header-anchor" href="#admin-ui" aria-label="Permalink to &quot;Admin UI&quot;">​</a></h3><ul><li><strong>URL-aware Settings Tabs</strong> — Tab switches update the browser URL via <code>history.replaceState</code></li><li><strong>Sidebar Collapse</strong> — &quot;Collapse Menu&quot; button; icon-only mode persisted in <code>localStorage</code> with no flash on navigation</li><li><strong>FalconCMS Branding</strong> — FCM logo in admin top bar</li></ul><h3 id="security-1" tabindex="-1">Security <a class="header-anchor" href="#security-1" aria-label="Permalink to &quot;Security&quot;">​</a></h3><ul><li><strong>HTTP Security Headers</strong> — <code>X-Content-Type-Options</code>, <code>X-Frame-Options</code>, <code>Referrer-Policy</code>, <code>Permissions-Policy</code>, CSP, HSTS</li><li><strong>Rate Limiting</strong> — Login, forgot-password, comments, cart operations, file downloads</li><li><strong>CSRF Protection</strong> — All state-changing routes protected</li><li><strong>Input Validation</strong> — Cart quantities, file uploads, comment length, user enumeration prevention</li><li><strong>Secure Downloads</strong> — Token-based file delivery; tokens expire and have per-user download limits</li></ul><h3 id="developer-tools" tabindex="-1">Developer Tools <a class="header-anchor" href="#developer-tools" aria-label="Permalink to &quot;Developer Tools&quot;">​</a></h3><ul><li><strong>Artisan Commands</strong> — <code>lazy:expire-sales</code> (scheduled sale price cleanup)</li><li><strong>REST API</strong> — Configurable API key authentication</li><li><strong>Backup &amp; Snapshots</strong> — Database and file backup tools</li><li><strong>WordPress Import</strong> — Import posts from a WordPress XML export</li><li><strong>Analytics Dashboard</strong> — Basic traffic and content stats</li><li><strong>Maintenance Mode</strong> — Toggle from Customizer with custom message and countdown timer</li></ul>',204))])}const y=r(c,[["render",u]]);export{w as __pageData,y as default};
